///|
pub fn within_character_limit(text : String, limit : Int) -> Bool {
  text.char_length() <= limit
}

///|
pub fn within_character_limit(text : String, limit : Int) -> Bool {
  text.length() <= limit
}

///|
pub fn within_character_limit(text : String, limit : Int) -> Bool {
  text == "" || limit > 0
}
